// Restrict inheritance to specific types
public sealed class Shape permits Circle, Square {
    // Core shared shape properties
}

public final class Circle extends Shape {}
public final class Square extends Shape {}

// Constructor, getters, equals, hashcode, toString in ONE line!
public record User(String name, int age) {
    // Compact constructor validator
    public User {
        if (age < 0) throw new IllegalArgumentException();
    }
}

// Cleaner type queries and nested object resolution
static String formatValue(Object obj) {
    return switch (obj) {
        case Integer i -> String.format("Integer value: %d", i);
        case String s  -> String.format("String value of len: %d", s.length());
        case null      -> "Value is null!";
        default        -> obj.toString();
    };
}

// No more backslashes or clumsy concatenation arrays
String jsonPayload = """
    {
        "status": "success",
        "data": {
            "version": "17.0.2",
            "environment": "Production"
        }
    }
    """;

// Switch and configure random generators easily
RandomGenerator generator = RandomGeneratorFactory
